export function phoneToState(phone: string | null | undefined): string | null {
  if (!phone) return null
  const digits = phone.replace(/\D/g, '')
  if (digits.length < 7) return null
  // Strip leading country code 52 if present
  const local = digits.startsWith('52') && digits.length >= 11 ? digits.slice(-10) : digits.slice(-10)
  const p2 = local.slice(0, 2)
  if (TWO_DIGIT_LADA[p2]) return TWO_DIGIT_LADA[p2]
  return THREE_DIGIT_LADA[local.slice(0, 3)] || null
}

export const ALL_STATES = Array.from(
  new Set([...Object.values(TWO_DIGIT_LADA), ...Object.values(THREE_DIGIT_LADA)])
).sort((a, b) => a.localeCompare(b, 'es'))

// Backward-compat alias (older code calls phoneToLocation)
export const phoneToLocation = phoneToState
